module ram_256x12 (
	R0_addr,
	R0_en,
	R0_clk,
	R0_data,
	W0_addr,
	W0_en,
	W0_clk,
	W0_data
);
	input [7:0] R0_addr;
	input R0_en;
	input R0_clk;
	output wire [11:0] R0_data;
	input [7:0] W0_addr;
	input W0_en;
	input W0_clk;
	input [11:0] W0_data;
	reg [11:0] Memory [0:255];
	always @(posedge W0_clk)
		if (W0_en & 1'h1)
			Memory[W0_addr] <= W0_data;
	assign R0_data = (R0_en ? Memory[R0_addr] : 12'bxxxxxxxxxxxx);
endmodule
module Queue256_BundleMap (
	clock,
	reset,
	io_enq_ready,
	io_enq_valid,
	io_enq_bits_tl_state_size,
	io_enq_bits_tl_state_source,
	io_deq_ready,
	io_deq_valid,
	io_deq_bits_tl_state_size,
	io_deq_bits_tl_state_source
);
	input clock;
	input reset;
	output wire io_enq_ready;
	input io_enq_valid;
	input [3:0] io_enq_bits_tl_state_size;
	input [7:0] io_enq_bits_tl_state_source;
	input io_deq_ready;
	output wire io_deq_valid;
	output wire [3:0] io_deq_bits_tl_state_size;
	output wire [7:0] io_deq_bits_tl_state_source;
	wire [11:0] _ram_ext_R0_data;
	wire io_enq_valid_0 = io_enq_valid;
	wire [3:0] io_enq_bits_tl_state_size_0 = io_enq_bits_tl_state_size;
	wire [7:0] io_enq_bits_tl_state_source_0 = io_enq_bits_tl_state_source;
	wire io_deq_ready_0 = io_deq_ready;
	wire [3:0] io_deq_bits_tl_state_size_0 = _ram_ext_R0_data[3:0];
	wire [7:0] io_deq_bits_tl_state_source_0 = _ram_ext_R0_data[11:4];
	reg [7:0] enq_ptr_value;
	reg [7:0] deq_ptr_value;
	reg maybe_full;
	wire ptr_match = enq_ptr_value == deq_ptr_value;
	wire empty = ptr_match & ~maybe_full;
	wire full = ptr_match & maybe_full;
	wire io_enq_ready_0;
	wire do_enq = io_enq_ready_0 & io_enq_valid_0;
	wire io_deq_valid_0;
	wire do_deq = io_deq_ready_0 & io_deq_valid_0;
	wire wrap = &enq_ptr_value;
	wire wrap_1 = &deq_ptr_value;
	assign io_deq_valid_0 = ~empty;
	assign io_enq_ready_0 = ~full;
	wire [7:0] ptr_diff = enq_ptr_value - deq_ptr_value;
	wire [8:0] io_count = {maybe_full & ptr_match, ptr_diff};
	always @(posedge clock)
		if (reset) begin
			enq_ptr_value <= 8'h00;
			deq_ptr_value <= 8'h00;
			maybe_full <= 1'h0;
		end
		else begin
			if (do_enq)
				enq_ptr_value <= enq_ptr_value + 8'h01;
			if (do_deq)
				deq_ptr_value <= deq_ptr_value + 8'h01;
			if (~(do_enq == do_deq))
				maybe_full <= do_enq;
		end
	ram_256x12 ram_ext(
		.R0_addr(deq_ptr_value),
		.R0_en(1'h1),
		.R0_clk(clock),
		.R0_data(_ram_ext_R0_data),
		.W0_addr(enq_ptr_value),
		.W0_en(do_enq),
		.W0_clk(clock),
		.W0_data({io_enq_bits_tl_state_source_0, io_enq_bits_tl_state_size_0})
	);
	assign io_enq_ready = io_enq_ready_0;
	assign io_deq_valid = io_deq_valid_0;
	assign io_deq_bits_tl_state_size = io_deq_bits_tl_state_size_0;
	assign io_deq_bits_tl_state_source = io_deq_bits_tl_state_source_0;
endmodule
